{
  "summary": "This paper introduces Multiple Choice Prompting (MCP) as a novel strategy for Large Language Model (LLM) based Multiple Choice Question Answering (MCQA), designed to overcome limitations of traditional Cloze Prompting (CP). It defines Multiple Choice Symbol Binding (MCSB) and demonstrates that LLMs with high MCSB (e.g., Codex) achieve significant performance gains with MCP across 20 diverse datasets, often approaching or exceeding state-of-the-art results. The authors argue that MCP allows for more explicit comparison of answer options and is more computationally efficient, suggesting that LLM capabilities in MCQA have been previously underestimated.",
  "strengths": [
    {
      "point": "Introduction of Multiple Choice Prompting (MCP) as an alternative to Cloze Prompting (CP)",
      "evidence": "The proposed approach presents the LLM with both the question and a list of candidate answer options, each associated with a symbol (e.g., 'A', 'B', 'C'). The LLM is prompted to output only the symbol corresponding to its chosen answer."
    },
    {
      "point": "Conceptualization of Multiple Choice Symbol Binding (MCSB) and proposal of the PPA metric",
      "evidence": "Key Requirement: Multiple Choice Symbol Binding (MCSB): For MCP to be effective, the LLM must possess the ability to consistently associate answer options with their corresponding symbols... MCSB Evaluation: The paper proposes the 'Proportion of Plurality Agreement' (PPA) metric to measure MCSB."
    },
    {
      "point": "Extensive empirical evaluation of MCP against CP across 20 diverse datasets",
      "evidence": "Results: ...Across 20 diverse datasets, MCP consistently outperformed CP for models with high MCSB (like Codex). MCP increased accuracy over CP by an average of 8.3% (zero-shot)..."
    },
    {
      "point": "Demonstration that prompting strategy significantly impacts LLM performance on MCQA, suggesting underestimated capabilities",
      "evidence": "Underestimation of LLMs for MCQA: The findings suggest that the true MCQA capabilities of LLMs have been previously underestimated due to the limitations of the CP prompting method."
    }
  ],
  "weaknesses": [
    {
      "point": "Underspecified novelty and differentiation of MCP from existing prompting paradigms (e.g., structured output generation or instruction following)",
      "evidence": "Proposed Method: Multiple Choice Prompting (MCP): The proposed approach presents the LLM with both the question and a list of candidate answer options, each associated with a symbol (e.g., 'A', 'B', 'C'). The LLM is prompted to output only the symbol corresponding to its chosen answer."
    },
    {
      "point": "Ambiguous and insufficient 'Formal Definition' of MCSB, with only PPA described as a metric rather than an axiomatic definition",
      "evidence": "Formal Definition of Multiple Choice Symbol Binding (MCSB): The concept of MCSB is formally defined and its importance for the effectiveness of MCP is highlighted."
    },
    {
      "point": "Lack of theoretical or empirical evidence for the internal mechanism of 'Explicit Comparison' claimed by MCP",
      "evidence": "Drawbacks of CP: ...Lack of Explicit Comparison: The LLM cannot directly compare different answer options... Proposed Method: ...Multiple Choice Prompting (MCP)..."
    },
    {
      "point": "Insufficient specification of the exact GPT-3 model variants used for comparisons, impacting reproducibility and rigor",
      "evidence": "Model Selection: Based on PPA scores, models like Codex (Davinci) and Instruct (Davinci) demonstrated significantly higher MCSB ability compared to GPT-3."
    },
    {
      "point": "Omission of absolute performance metrics for both MCP and CP across datasets, making the practical impact of gains hard to assess",
      "evidence": "Results: ...MCP increased accuracy over CP by an average of 8.3% (zero-shot), 12.2% (one-shot), and 9.7% (few-shot)."
    },
    {
      "point": "Ambiguous definition of 'previous SOTA' for benchmarking, unclear if it refers to LLM-specific or general task-specific models",
      "evidence": "Results: ...On average across all datasets, MCP scored within a percentage point of previous SOTA."
    },
    {
      "point": "Unquantified computational expense of Cloze Prompting (CP), making efficiency claims difficult to verify",
      "evidence": "Drawbacks of CP: ...Computational Expense: CP requires multiple forward passes through the LLM for each answer option, making it inefficient."
    },
    {
      "point": "Post-hoc rationalization for datasets where CP outperformed MCP, lacking *a priori* identification of predictive characteristics",
      "evidence": "Exceptions: CP outperformed MCP on four datasets (AG News, PIQA, RiddleSense, Winogrande). This was attributed to these datasets having short, often single-word answers where CP acted more like MCP, or where questions were particularly 'cloze-friendly' (PIQA)."
    },
    {
      "point": "Reliance on proprietary models (Codex 'free beta') and unsubstantiated justification for Codex's performance via code training",
      "evidence": "Model Selection: Codex was chosen for further evaluation due to its high PPA, cost-effectiveness (free beta), and training focus on code which likely enhances symbol binding."
    },
    {
      "point": "Insufficient granular analysis of dataset characteristics beyond broad categories, limiting insights into MCP's strengths and weaknesses",
      "evidence": "Exceptions: ...This was attributed to these datasets having short, often single-word answers where CP acted more like MCP, or where questions were particularly 'cloze-friendly' (PIQA)."
    },
    {
      "point": "Unaddressed 'ground truth' problem for PPA, as the 'most frequent answer' might not correspond to the correct label",
      "evidence": "MCSB Evaluation: The paper proposes the 'Proportion of Plurality Agreement' (PPA) metric to measure MCSB. PPA calculates the percentage of answer orderings for which a model selects the most frequent answer across all orderings."
    },
    {
      "point": "Unaddressed problem of invalid or hallucinated answer options within the multiple-choice selection process",
      "evidence": "Proposed Method: The proposed approach presents the LLM with both the question and a list of candidate answer options..."
    },
    {
      "point": "Limited analysis of how prompting strategy interacts with LLM scale or specific architectural properties for generalizability",
      "evidence": "Model Comparison: Codex and Instruct models consistently outperformed GPT-3 across tasks when using MCP."
    }
  ],
  "questions": [
    {
      "question": "How sensitive is MCP's performance to variations in prompt engineering (e.g., phrasing, instructions)?",
      "motivation": "Without this exploration, the reported results might be specific to a single, potentially suboptimal, prompt formulation, and its generalizability is questionable."
    },
    {
      "question": "Could simpler aggregation techniques for CP (e.g., averaging probabilities, majority vote across re-ordered prompts) achieve similar performance gains as MCP?",
      "motivation": "This comparison is crucial to ascertain if MCP is truly the most efficient or simplest way to overcome CP's limitations, or if similar benefits could be reaped from existing methods."
    }
  ],
  "scores": {
    "correctness": 2,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 4
  }
}
